import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const x=JSON.parse('{"title":"故宫博物院","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/forbidden-city.md","filePath":"landmarks/forbidden-city.md","lastUpdated":null}'),n={name:"landmarks/forbidden-city.md"};function d(o,t,i,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="故宫博物院" tabindex="-1">故宫博物院 <a class="header-anchor" href="#故宫博物院" aria-label="Permalink to &quot;故宫博物院&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1599661046289-e31897846e41?w=1200" alt="故宫"></p><blockquote><p>&quot;金碧辉煌紫禁城，红墙宫里万重门。&quot; —— 唐代诗人 王建</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>故宫博物院，旧称紫禁城，是明清两代的皇家宫殿，位于北京中轴线的中心。它是世界上现存规模最大、保存最为完整的木质结构古建筑群之一，被誉为世界五大宫之首（北京故宫、法国凡尔赛宫、英国白金汉宫、美国白宫、俄罗斯克里姆林宫）。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">8:30-17:00（淡季至16:30），周一闭馆（法定节假日除外）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">旺季60元，淡季40元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">半天至一天</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春秋两季</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线天安门东/西站</td></tr><tr><td style="text-align:left;"><strong>预约方式</strong></td><td style="text-align:left;">故宫博物院官网或微信公众号提前7天预约</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="营建历史" tabindex="-1">营建历史 <a class="header-anchor" href="#营建历史" aria-label="Permalink to &quot;营建历史&quot;">​</a></h3><p>明永乐四年（1406年），明成祖朱棣下诏营建北京宫殿。永乐十八年（1420年）建成，正式迁都北京。故宫占地面积72万平方米，建筑面积约15万平方米，有大小宫殿七十多座，房屋九千余间。</p><h3 id="朝代更迭" tabindex="-1">朝代更迭 <a class="header-anchor" href="#朝代更迭" aria-label="Permalink to &quot;朝代更迭&quot;">​</a></h3><ul><li><strong>明朝（1420-1644）</strong>：14位皇帝在此居住</li><li><strong>清朝（1644-1911）</strong>：10位皇帝在此居住</li><li><strong>民国时期（1912-1924）</strong>：溥仪退位后仍居宫中</li><li><strong>故宫博物院（1925至今）</strong>：1925年10月10日正式成立</li></ul><h2 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h2><p>故宫按照&quot;前朝后寝&quot;的制度布局，分为外朝和内廷两部分：</p><h3 id="外朝-前朝" tabindex="-1">外朝（前朝） <a class="header-anchor" href="#外朝-前朝" aria-label="Permalink to &quot;外朝（前朝）&quot;">​</a></h3><p>以太和殿、中和殿、保和殿为中心，是皇帝举行大典、处理朝政的地方。</p><table tabindex="0"><thead><tr><th style="text-align:left;">宫殿</th><th style="text-align:left;">功能</th><th style="text-align:left;">看点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>太和殿</strong></td><td style="text-align:left;">举行大典</td><td style="text-align:left;">金銮宝座、龙纹装饰</td></tr><tr><td style="text-align:left;"><strong>中和殿</strong></td><td style="text-align:left;">休息准备</td><td style="text-align:left;">皇帝大典前小憩</td></tr><tr><td style="text-align:left;"><strong>保和殿</strong></td><td style="text-align:left;">宴饮科举</td><td style="text-align:left;">清代殿试场所</td></tr></tbody></table><h3 id="内廷-后寝" tabindex="-1">内廷（后寝） <a class="header-anchor" href="#内廷-后寝" aria-label="Permalink to &quot;内廷（后寝）&quot;">​</a></h3><p>以乾清宫、交泰殿、坤宁宫为中心，是皇帝和后妃居住的地方。</p><table tabindex="0"><thead><tr><th style="text-align:left;">宫殿</th><th style="text-align:left;">功能</th><th style="text-align:left;">看点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>乾清宫</strong></td><td style="text-align:left;">皇帝寝宫</td><td style="text-align:left;">&quot;正大光明&quot;匾额、秘密立储</td></tr><tr><td style="text-align:left;"><strong>交泰殿</strong></td><td style="text-align:left;">皇后起居</td><td style="text-align:left;">存放玉玺</td></tr><tr><td style="text-align:left;"><strong>坤宁宫</strong></td><td style="text-align:left;">皇后寝宫</td><td style="text-align:left;">萨满祭祀</td></tr><tr><td style="text-align:left;"><strong>御花园</strong></td><td style="text-align:left;">皇家园林</td><td style="text-align:left;">堆秀山、摛藻堂</td></tr></tbody></table><h2 id="必看珍宝" tabindex="-1">必看珍宝 <a class="header-anchor" href="#必看珍宝" aria-label="Permalink to &quot;必看珍宝&quot;">​</a></h2><h3 id="钟表馆" tabindex="-1">钟表馆 <a class="header-anchor" href="#钟表馆" aria-label="Permalink to &quot;钟表馆&quot;">​</a></h3><p>奉先殿钟表馆收藏中外钟表200余件，有英国、法国、瑞士、日本及中国清宫造办处制造的各式钟表，体现了18-20世纪世界钟表制造的顶尖水平。</p><h3 id="珍宝馆" tabindex="-1">珍宝馆 <a class="header-anchor" href="#珍宝馆" aria-label="Permalink to &quot;珍宝馆&quot;">​</a></h3><p>宁寿宫珍宝馆展示清代宫廷制作及收藏的珍贵文物，包括金器、银器、玉器、宝石、珍珠、翡翠、珊瑚等。</p><h3 id="石鼓馆" tabindex="-1">石鼓馆 <a class="header-anchor" href="#石鼓馆" aria-label="Permalink to &quot;石鼓馆&quot;">​</a></h3><p>收藏被誉为&quot;石刻之祖&quot;的十面先秦石鼓，是中国最早的石刻文字之一。</p><h2 id="文化故事" tabindex="-1">文化故事 <a class="header-anchor" href="#文化故事" aria-label="Permalink to &quot;文化故事&quot;">​</a></h2><h3 id="正大光明-匾额" tabindex="-1">&quot;正大光明&quot;匾额 <a class="header-anchor" href="#正大光明-匾额" aria-label="Permalink to &quot;&quot;正大光明&quot;匾额&quot;">​</a></h3><p>乾清宫&quot;正大光明&quot;匾额是顺治皇帝御笔亲书。自雍正皇帝开始，这块匾额背后成为秘密立储诏书的存放处。皇帝生前将继承人名字写好，密封藏于匾后，驾崩后当众取出宣读。</p><h3 id="九龙壁" tabindex="-1">九龙壁 <a class="header-anchor" href="#九龙壁" aria-label="Permalink to &quot;九龙壁&quot;">​</a></h3><p>九龙壁位于皇极门外，是一座长29.4米、高3.5米的琉璃照壁。壁上九条龙栩栩如生，形态各异，展现了高超的工艺水平。传说当年烧制时有一块构件不慎烧坏，工匠用楠木雕制补上，瞒过了乾隆皇帝的检查。</p><h3 id="珍妃井" tabindex="-1">珍妃井 <a class="header-anchor" href="#珍妃井" aria-label="Permalink to &quot;珍妃井&quot;">​</a></h3><p>珍妃井位于东北角贞顺门内。1900年八国联军攻入北京时，慈禧太后命人将光绪皇帝宠爱的珍妃推入此井溺死。这口井成为宫廷斗争悲剧的见证。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>半日游路线（约4小时）</strong>：</p><p>午门 → 太和门 → 太和殿 → 中和殿 → 保和殿 → 乾清门 → 乾清宫 → 交泰殿 → 坤宁宫 → 御花园 → 神武门</p><p><strong>一日游路线（约6-8小时）</strong>：</p><p>午门 → 武英殿（陶瓷馆） → 太和门 → 太和殿 → 中和殿 → 保和殿 → 钟表馆 → 珍宝馆 → 东六宫 → 乾清门 → 乾清宫 → 交泰殿 → 坤宁宫 → 御花园 → 西六宫 → 神武门</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>提前预约</strong>：必须提前在官网或微信预约，现场不售票</li><li><strong>避开人流</strong>：上午10点前或下午3点后入场，避开旅行团高峰</li><li><strong>穿着舒适</strong>：需要大量步行，建议穿舒适鞋子</li><li><strong>讲解服务</strong>：可租借语音导览（20元）或请人工讲解（150-350元）</li><li><strong>拍摄建议</strong>：清晨和傍晚光线最佳，红墙黄瓦非常适合拍照</li></ol><h2 id="周边美食" tabindex="-1">周边美食 <a class="header-anchor" href="#周边美食" aria-label="Permalink to &quot;周边美食&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">餐厅</th><th style="text-align:left;">特色</th><th style="text-align:left;">地址</th></tr></thead><tbody><tr><td style="text-align:left;">四季民福烤鸭</td><td style="text-align:left;">北京烤鸭</td><td style="text-align:left;">故宫东华门外</td></tr><tr><td style="text-align:left;">护国寺小吃</td><td style="text-align:left;">北京传统小吃</td><td style="text-align:left;">新街口</td></tr><tr><td style="text-align:left;">海碗居</td><td style="text-align:left;">老北京炸酱面</td><td style="text-align:left;">松榆西里</td></tr><tr><td style="text-align:left;">姚记炒肝</td><td style="text-align:left;">炒肝、包子</td><td style="text-align:left;">鼓楼东大街</td></tr></tbody></table><hr><p><strong>📍 地址</strong>：北京市东城区景山前街4号 <strong>📞 电话</strong>：010-85007421 <strong>🌐 官网</strong>：<a href="https://www.dpm.org.cn" target="_blank" rel="noreferrer">www.dpm.org.cn</a></p>',46)])])}const b=e(n,[["render",d]]);export{x as __pageData,b as default};
